-- Volcando estructura para tabla retenciones_sifen.retenciones_enviadas
CREATE TABLE IF NOT EXISTS `retenciones_enviadas` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_factura_orig` bigint(20) DEFAULT NULL,
  `orden_pago` bigint(20) DEFAULT NULL,
  `nro_comprobante` varchar(50) DEFAULT NULL,
  `ruc_proveedor` varchar(20) DEFAULT NULL,
  `razon_social` varchar(200) DEFAULT NULL,
  `concepto` varchar(300) DEFAULT NULL,
  `fecha_factura` date DEFAULT NULL,
  `monto` decimal(18,2) DEFAULT NULL,
  `moneda` varchar(5) DEFAULT NULL,
  `factor_cambio` decimal(12,2) DEFAULT NULL,
  `retencion` decimal(18,2) DEFAULT NULL,
  `estado` varchar(30) DEFAULT NULL,
  `cdc` varchar(100) DEFAULT NULL,
  `motivo_rechazo` text DEFAULT NULL,
  `fecha_envio` datetime DEFAULT NULL,
  `usuario` varchar(50) DEFAULT NULL,
  `fecha_creacion` datetime DEFAULT current_timestamp(),
  `num_timbrado` varchar(20) DEFAULT NULL COMMENT 'Timbrado del comprobante de retencion DUTRIEC',
  `timbrado_proveedor` varchar(20) DEFAULT NULL,
  `correo_proveedor` varchar(150) DEFAULT NULL COMMENT 'Email del proveedor (SQL Anywhere)',
  `telefono_proveedor` varchar(50) DEFAULT NULL COMMENT 'Telefono del proveedor (SQL Anywhere)',
  `direccion_proveedor` varchar(250) DEFAULT NULL COMMENT 'Direccion del proveedor (SQL Anywhere)',
  `estado_envio_tesaka` varchar(30) DEFAULT NULL COMMENT 'PENDIENTE / TESAKA_ENVIADO / APROBADA / RECHAZADA',
  `aprobacion_estado` varchar(50) DEFAULT NULL,
  `aprobacion_nro_control` varchar(100) DEFAULT NULL,
  `aprobacion_comentario` text DEFAULT NULL,
  `fecha_actualizacion` datetime DEFAULT NULL,
  `veces_revertida` int(11) NOT NULL DEFAULT 0,
  `veces_rechazada` int(11) NOT NULL DEFAULT 0,
  `revertido_por` int(11) DEFAULT NULL,
  `motivo_reversion` varchar(255) DEFAULT NULL,
  `fecha_reversion` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_factura_orig` (`id_factura_orig`),
  KEY `idx_ret_estado` (`estado`),
  KEY `idx_ret_factura_orig` (`id_factura_orig`),
  KEY `idx_ret_nro_comp` (`nro_comprobante`),
  KEY `idx_ret_fecha_creacion` (`fecha_creacion`)
) ENGINE=InnoDB AUTO_INCREMENT=65 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;

