-- Volcando estructura para tabla retenciones_sifen.seq_num_doc_ret
CREATE TABLE IF NOT EXISTS `seq_num_doc_ret` (
  `establecimiento` varchar(3) NOT NULL,
  `punto_expedicion` varchar(3) NOT NULL,
  `ultimo_numero` bigint(20) NOT NULL DEFAULT 0,
  PRIMARY KEY (`establecimiento`,`punto_expedicion`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;

-- Volcando datos para la tabla retenciones_sifen.seq_num_doc_ret: ~1 rows (aproximadamente)
INSERT INTO `seq_num_doc_ret` (`establecimiento`, `punto_expedicion`, `ultimo_numero`) VALUES
	('001', '001', 65);

-- Volcando estructura para procedimiento retenciones_sifen.sp_siguiente_num_doc_ret
DELIMITER //
CREATE PROCEDURE `sp_siguiente_num_doc_ret`(
    IN  p_establecimiento  VARCHAR(3),
    IN  p_punto_expedicion VARCHAR(3),
    OUT p_num_doc_ret      VARCHAR(20)
)
BEGIN
    DECLARE v_siguiente BIGINT DEFAULT 1;

    -- Insertar fila si no existe aun para este est/punto
    INSERT IGNORE INTO seq_num_doc_ret (establecimiento, punto_expedicion, ultimo_numero)
    VALUES (p_establecimiento, p_punto_expedicion, 0);

    -- Incrementar de forma atomica
    UPDATE seq_num_doc_ret
    SET    ultimo_numero = ultimo_numero + 1
    WHERE  establecimiento  = p_establecimiento
      AND  punto_expedicion = p_punto_expedicion;

    -- Leer el valor recien incrementado
    SELECT ultimo_numero
    INTO   v_siguiente
    FROM   seq_num_doc_ret
    WHERE  establecimiento  = p_establecimiento
      AND  punto_expedicion = p_punto_expedicion;

    -- Formato: 001-001-0000001 (7 digitos con cero a izquierda)
    SET p_num_doc_ret = CONCAT(
        p_establecimiento, '-',
        p_punto_expedicion, '-',
        LPAD(v_siguiente, 7, '0')
    );
END//
DELIMITER ;

-- Volcando estructura para tabla retenciones_sifen.usuarios
CREATE TABLE IF NOT EXISTS `usuarios` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `nombre` varchar(120) DEFAULT NULL,
  `rol` enum('SOPORTE','JEFE','ASISTENTE') NOT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `creado_por` int(11) DEFAULT NULL,
  `fecha_creacion` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  KEY `fk_usuarios_creador` (`creado_por`),
  CONSTRAINT `fk_usuarios_creador` FOREIGN KEY (`creado_por`) REFERENCES `usuarios` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;

